public static class FinanceMapper {
 public static AccountDto ToDto(this Account x){var available=x.Type==AccountType.CreditCard?Math.Max(0,x.CreditLimit-x.CurrentBalance):x.CurrentBalance; return new(x.Id,x.Name,x.Type,x.InitialBalance,x.CurrentBalance,x.Color,x.IsArchived,x.CreditLimit,x.ClosingDay,x.DueDay,available,x.Type==AccountType.CreditCard?x.CurrentBalance:0);}
 public static CategoryDto ToDto(this Category x)=>new(x.Id,x.Name,x.Type,x.Color,x.Icon,x.IsDefault);
 public static TransactionDto ToDto(this Transaction x)=>new(x.Id,x.AccountId,x.CategoryId,x.Description,x.Amount,x.Type,x.Status,x.Date,x.DueDate,x.Notes,x.CreditCardInvoiceId,x.IsRecurring,x.RecurrenceType,x.RecurrenceInterval,x.RecurrenceEndDate,x.RecurrenceGroupId,x.RecurrenceIndex,x.TotalInstallments);
 public static UpcomingDueDto ToUpcomingDueDto(this Transaction x){var today=DateTime.UtcNow.Date; var due=x.DueDate?.Date??x.Date.Date; var days=(int)(due-today).TotalDays; return new(x.Id,x.AccountId,x.CategoryId,x.Description,x.Amount,x.Type,x.Status,x.Date,x.DueDate,x.Notes,x.CreditCardInvoiceId,x.IsRecurring,x.RecurrenceType,x.RecurrenceInterval,x.RecurrenceEndDate,x.RecurrenceGroupId,x.RecurrenceIndex,x.TotalInstallments,days);}
 public static TransferDto ToDto(this Transfer x)=>new(x.Id,x.FromAccountId,x.ToAccountId,x.Amount,x.Date,x.Description,x.Status);
 public static CreditCardInvoiceDto ToDto(this CreditCardInvoice x,List<Transaction> transactions)=>new(x.Id,x.AccountId,x.Month,x.Year,x.TotalAmount,x.Status,x.DueDate,x.PaidAt,transactions.Select(t=>t.ToDto()).ToList());
 public static decimal Impact(TransactionType t, decimal amount)=> t==TransactionType.Income ? amount : -amount;
}

public static class CreditCardInvoiceCalculator {
 public static (int Month,int Year) Period(DateTime date,int closingDay){var period=new DateTime(date.Year,date.Month,1); if(date.Day>closingDay) period=period.AddMonths(1); return (period.Month,period.Year);}
 public static DateTime DueDate(int month,int year,int dueDay)=>new(year,month,Math.Clamp(dueDay,1,28));
}

public static class RecurrenceGenerator {
 public static List<Transaction> Generate(CreateTransactionCommand c){var groupId=Guid.NewGuid(); var type=c.TotalInstallments.HasValue?Domain.Enums.RecurrenceType.Monthly:c.RecurrenceType??Domain.Enums.RecurrenceType.Monthly; var interval=Math.Max(1,c.RecurrenceInterval); var total=c.TotalInstallments??CalculateOpenEndedCount(c.Date,c.RecurrenceEndDate,type,interval); var list=new List<Transaction>(); for(var i=0;i<total;i++){var date=AddInterval(c.Date,type,interval,i); if(c.RecurrenceEndDate.HasValue&&date.Date>c.RecurrenceEndDate.Value.Date) break; list.Add(new Transaction{UserId=c.UserId,AccountId=c.AccountId,CategoryId=c.CategoryId,Description=c.TotalInstallments.HasValue?$"{c.Description} ({i+1}/{total})":c.Description,Amount=c.Amount,Type=c.Type,Status=i==0?c.Status:TransactionStatus.Pending,Date=date,DueDate=c.DueDate.HasValue?AddInterval(c.DueDate.Value,type,interval,i):null,Notes=c.Notes,IsRecurring=true,RecurrenceType=type,RecurrenceInterval=interval,RecurrenceEndDate=c.RecurrenceEndDate,RecurrenceGroupId=groupId,RecurrenceIndex=i+1,TotalInstallments=c.TotalInstallments});} return list;}
 public static DateTime AddInterval(DateTime date,RecurrenceType type,int interval,int index)=>type switch{RecurrenceType.Weekly=>date.AddDays(7*interval*index),RecurrenceType.Yearly=>date.AddYears(interval*index),_=>date.AddMonths(interval*index)};
 static int CalculateOpenEndedCount(DateTime start,DateTime? end,RecurrenceType type,int interval){var limit=end?.Date??start.AddMonths(12).Date; var count=0; var current=start; while(current.Date<=limit&&count<60){count++; current=AddInterval(start,type,interval,count);} return Math.Max(count,1);}
}

public static class TransactionPostingService {
 public static async Task<Transaction> PostAsync(Transaction tx,ITransactionRepository txRepo,IAccountRepository accRepo,ICategoryRepository catRepo,ICreditCardInvoiceRepository invoiceRepo,string userId){var acc=await accRepo.GetByIdAsync(tx.AccountId,userId)??throw new ValidationException("Conta invalida"); if(!string.IsNullOrWhiteSpace(tx.CategoryId)) _=await catRepo.GetByIdAsync(tx.CategoryId,userId)??throw new ValidationException("Categoria invalida"); if(acc.Type==AccountType.CreditCard&&tx.Type==TransactionType.Expense){var period=CreditCardInvoiceCalculator.Period(tx.Date,acc.ClosingDay); var invoice=await invoiceRepo.GetByPeriodAsync(acc.Id,userId,period.Month,period.Year); if(invoice is null){invoice=new CreditCardInvoice{UserId=userId,AccountId=acc.Id,Month=period.Month,Year=period.Year,DueDate=CreditCardInvoiceCalculator.DueDate(period.Month,period.Year,acc.DueDay)}; await invoiceRepo.AddAsync(invoice);} invoice.TotalAmount+=tx.Amount; await invoiceRepo.UpdateAsync(invoice); tx.Status=TransactionStatus.Pending; tx.CreditCardInvoiceId=invoice.Id; acc.CurrentBalance=await invoiceRepo.SumOpenByAccountAsync(acc.Id,userId); await accRepo.UpdateAsync(acc);} else if(tx.Status==TransactionStatus.Paid){acc.CurrentBalance+=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(acc);} await txRepo.AddAsync(tx); return tx;}
}

public class GetAccountsHandler(IAccountRepository r):IRequestHandler<GetAccountsQuery,List<AccountDto>>{public async Task<List<AccountDto>> Handle(GetAccountsQuery q,CancellationToken ct)=>(await r.GetByUserAsync(q.UserId)).Select(x=>x.ToDto()).ToList();}
public class GetAccountByIdHandler(IAccountRepository r):IRequestHandler<GetAccountByIdQuery,AccountDto>{public async Task<AccountDto> Handle(GetAccountByIdQuery q,CancellationToken ct)=>(await r.GetByIdAsync(q.Id,q.UserId)??throw new NotFoundException("Conta nao encontrada")).ToDto();}
public class CreateAccountHandler(IAccountRepository r):IRequestHandler<CreateAccountCommand,AccountDto>{public async Task<AccountDto> Handle(CreateAccountCommand c,CancellationToken ct){ValidateCreditCard(c.Type,c.CreditLimit,c.ClosingDay,c.DueDay); var current=c.Type==AccountType.CreditCard?0:c.InitialBalance; var a=new Account{UserId=c.UserId,Name=c.Name,Type=c.Type,InitialBalance=c.InitialBalance,CurrentBalance=current,Color=c.Color,CreditLimit=c.Type==AccountType.CreditCard?c.CreditLimit:0,ClosingDay=c.ClosingDay,DueDay=c.DueDay}; await r.AddAsync(a); return a.ToDto();} static void ValidateCreditCard(AccountType type,decimal limit,int closingDay,int dueDay){if(type!=AccountType.CreditCard) return; if(limit<=0) throw new ValidationException("Limite do cartao deve ser positivo"); if(closingDay<1||closingDay>28||dueDay<1||dueDay>28) throw new ValidationException("Fechamento e vencimento devem estar entre 1 e 28");}}
public class UpdateAccountHandler(IAccountRepository r):IRequestHandler<UpdateAccountCommand,AccountDto>{public async Task<AccountDto> Handle(UpdateAccountCommand c,CancellationToken ct){var a=await r.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Conta nao encontrada"); if(c.Type==AccountType.CreditCard){if(c.CreditLimit<=0) throw new ValidationException("Limite do cartao deve ser positivo"); if(c.ClosingDay<1||c.ClosingDay>28||c.DueDay<1||c.DueDay>28) throw new ValidationException("Fechamento e vencimento devem estar entre 1 e 28");} a.Name=c.Name;a.Type=c.Type;a.Color=c.Color;a.IsArchived=c.IsArchived;a.CreditLimit=c.Type==AccountType.CreditCard?c.CreditLimit:0;a.ClosingDay=c.ClosingDay;a.DueDay=c.DueDay; await r.UpdateAsync(a); return a.ToDto();}}
public class ArchiveAccountHandler(IAccountRepository r):IRequestHandler<ArchiveAccountCommand>{public async Task Handle(ArchiveAccountCommand c,CancellationToken ct){var a=await r.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Conta nao encontrada"); a.IsArchived=true; await r.UpdateAsync(a);}}
public class DeleteAccountHandler(IAccountRepository r,ITransactionRepository tr):IRequestHandler<DeleteAccountCommand>{public async Task Handle(DeleteAccountCommand c,CancellationToken ct){if(await tr.ExistsByAccountIdAsync(c.Id,c.UserId)) throw new ConflictException("Conta possui transacoes vinculadas"); await r.DeleteAsync(c.Id,c.UserId);}}

