public class GetTransactionsHandler(ITransactionRepository r):IRequestHandler<GetTransactionsQuery,PagedResultDto<TransactionDto>>{public async Task<PagedResultDto<TransactionDto>> Handle(GetTransactionsQuery q,CancellationToken ct){var page=q.Page<1?1:q.Page; var pageSize=q.PageSize<1?20:(q.PageSize>200?200:q.PageSize); var filter=new TransactionFilter(q.UserId,q.Month,q.Year,q.Type,q.Status,q.CategoryId,q.AccountId,q.Search,q.DateFrom,q.DateTo,q.AccountIds,q.CategoryIds,q.MinAmount,q.MaxAmount); var (items,total)=await r.GetPagedAsync(filter,page,pageSize); var totalPages=pageSize<=0?0:(int)Math.Ceiling(total/(double)pageSize); return new PagedResultDto<TransactionDto>(items.Select(x=>x.ToDto()).ToList(),total,page,pageSize,totalPages);}}
public class ExportTransactionsCsvHandler(ITransactionRepository txRepo, IAccountRepository accRepo, ICategoryRepository catRepo): IRequestHandler<ExportTransactionsCsvQuery,TransactionsCsvFile>{
 public async Task<TransactionsCsvFile> Handle(ExportTransactionsCsvQuery q, CancellationToken ct){
  var filter=new TransactionFilter(q.UserId,q.Month,q.Year,q.Type,q.Status,q.CategoryId,q.AccountId,null,q.DateFrom,q.DateTo,null,null,null,null);
  var (items,_)=await txRepo.GetPagedAsync(filter, 1, int.MaxValue);
  var accounts=(await accRepo.GetByUserAsync(q.UserId)).ToDictionary(x=>x.Id,x=>x.Name);
  var categories=(await catRepo.GetByUserAsync(q.UserId)).ToDictionary(x=>x.Id,x=>x.Name);
  var sb=new System.Text.StringBuilder();
  sb.AppendLine("Data;Descricao;Tipo;Categoria;Conta;Valor;Status;Vencimento;Notas");
  foreach(var tx in items.OrderByDescending(x=>x.Date)){
   var row=string.Join(";", new[]{
    tx.Date.ToString("yyyy-MM-dd"),
    CsvEscape(tx.Description),
    tx.Type.ToString(),
    CsvEscape(categories.GetValueOrDefault(tx.CategoryId, "")),
    CsvEscape(accounts.GetValueOrDefault(tx.AccountId, "")),
    tx.Amount.ToString(System.Globalization.CultureInfo.InvariantCulture),
    tx.Status.ToString(),
    tx.DueDate?.ToString("yyyy-MM-dd") ?? "",
    CsvEscape(tx.Notes ?? "")
   });
   sb.AppendLine(row);
  }
  var monthLabel=(q.DateFrom?.Month ?? q.Month ?? DateTime.UtcNow.Month).ToString("00");
  var yearLabel=(q.DateFrom?.Year ?? q.Year ?? DateTime.UtcNow.Year).ToString();
  return new TransactionsCsvFile($"aurora-transacoes-{monthLabel}-{yearLabel}.csv", sb.ToString());
 }
 static string CsvEscape(string value){if(string.IsNullOrEmpty(value)) return ""; var needsQuotes=value.Contains(';')||value.Contains('"')||value.Contains('\n')||value.Contains('\r'); var escaped=value.Replace("\"","\"\""); return needsQuotes?$"\"{escaped}\"":escaped;}
}
public class GetTransactionByIdHandler(ITransactionRepository r):IRequestHandler<GetTransactionByIdQuery,TransactionDto>{public async Task<TransactionDto> Handle(GetTransactionByIdQuery q,CancellationToken ct)=>(await r.GetByIdAsync(q.Id,q.UserId)??throw new NotFoundException("Transacao nao encontrada")).ToDto();}
public class CreateTransactionHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICategoryRepository catRepo,ICreditCardInvoiceRepository invoiceRepo,ICacheService cache): IRequestHandler<CreateTransactionCommand,TransactionDto>{public async Task<TransactionDto> Handle(CreateTransactionCommand c,CancellationToken ct){if(c.Amount<=0) throw new ValidationException("Amount deve ser positivo"); var transactions=c.IsRecurring||c.TotalInstallments.HasValue?RecurrenceGenerator.Generate(c):[new Transaction{UserId=c.UserId,AccountId=c.AccountId,CategoryId=c.CategoryId,Description=c.Description,Amount=c.Amount,Type=c.Type,Status=c.Status,Date=c.Date,DueDate=c.DueDate,Notes=c.Notes}]; TransactionDto? first=null; foreach(var tx in transactions){var saved=await TransactionPostingService.PostAsync(tx,txRepo,accRepo,catRepo,invoiceRepo,c.UserId); first??=saved.ToDto();} await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return first!;}}
public class UpdateTransactionHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICategoryRepository catRepo,ICacheService cache): IRequestHandler<UpdateTransactionCommand,TransactionDto>{public async Task<TransactionDto> Handle(UpdateTransactionCommand c,CancellationToken ct){if(c.Amount<=0) throw new ValidationException("Amount deve ser positivo"); var tx=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); var oldAcc=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta antiga invalida"); var newAcc=await accRepo.GetByIdAsync(c.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); _=await catRepo.GetByIdAsync(c.CategoryId,c.UserId)??throw new ValidationException("Categoria invalida"); if(tx.Status==TransactionStatus.Paid&&oldAcc.Type!=AccountType.CreditCard){oldAcc.CurrentBalance-=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(oldAcc);} tx.AccountId=c.AccountId;tx.CategoryId=c.CategoryId;tx.Description=c.Description;tx.Amount=c.Amount;tx.Type=c.Type;tx.Status=c.Status;tx.Date=c.Date;tx.DueDate=c.DueDate;tx.Notes=c.Notes; if(tx.Status==TransactionStatus.Paid&&newAcc.Type!=AccountType.CreditCard){newAcc.CurrentBalance+=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(newAcc);} await txRepo.UpdateAsync(tx); await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return tx.ToDto();}}
public class DeleteTransactionHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICreditCardInvoiceRepository invoiceRepo,ICacheService cache):IRequestHandler<DeleteTransactionCommand>{public async Task Handle(DeleteTransactionCommand c,CancellationToken ct){var tx=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); var acc=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); if(acc.Type==AccountType.CreditCard&&!string.IsNullOrWhiteSpace(tx.CreditCardInvoiceId)){var invoice=await invoiceRepo.GetByIdAsync(tx.CreditCardInvoiceId,c.UserId); if(invoice is not null&&invoice.Status!=CreditCardInvoiceStatus.Paid){invoice.TotalAmount=Math.Max(0,invoice.TotalAmount-tx.Amount); await invoiceRepo.UpdateAsync(invoice); acc.CurrentBalance=await invoiceRepo.SumOpenByAccountAsync(acc.Id,c.UserId); await accRepo.UpdateAsync(acc);}} else if(tx.Status==TransactionStatus.Paid){acc.CurrentBalance-=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(acc);} await txRepo.DeleteAsync(tx.Id,c.UserId); await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct);}}
public class MarkTransactionAsPaidHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICacheService cache):IRequestHandler<MarkTransactionAsPaidCommand,TransactionDto>{public async Task<TransactionDto> Handle(MarkTransactionAsPaidCommand c,CancellationToken ct){var tx=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); if(tx.Status!=TransactionStatus.Paid){var acc=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); if(acc.Type!=AccountType.CreditCard){acc.CurrentBalance+=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(acc);} tx.Status=TransactionStatus.Paid; await txRepo.UpdateAsync(tx);} await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return tx.ToDto();}}
public class MarkTransactionAsPendingHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICacheService cache):IRequestHandler<MarkTransactionAsPendingCommand,TransactionDto>{public async Task<TransactionDto> Handle(MarkTransactionAsPendingCommand c,CancellationToken ct){var tx=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); if(tx.Status==TransactionStatus.Paid){var acc=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); if(acc.Type!=AccountType.CreditCard){acc.CurrentBalance-=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(acc);}} tx.Status=TransactionStatus.Pending; await txRepo.UpdateAsync(tx); await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return tx.ToDto();}}
public class UpdateRecurringTransactionHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICategoryRepository catRepo,ICacheService cache):IRequestHandler<UpdateRecurringTransactionCommand,List<TransactionDto>>{public async Task<List<TransactionDto>> Handle(UpdateRecurringTransactionCommand c,CancellationToken ct){var selected=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); var targets=await RecurrenceScope.SelectAsync(txRepo,selected,c.UserId,c.Scope); foreach(var tx in targets){tx.AccountId=c.AccountId;tx.CategoryId=c.CategoryId;tx.Description=tx.TotalInstallments.HasValue&&tx.RecurrenceIndex.HasValue?$"{StripInstallmentSuffix(c.Description)} ({tx.RecurrenceIndex}/{tx.TotalInstallments})":c.Description;tx.Amount=c.Amount;tx.Type=c.Type;tx.Status=c.Status;tx.DueDate=c.DueDate.HasValue?RecurrenceGenerator.AddInterval(c.DueDate.Value,c.RecurrenceType??tx.RecurrenceType??Domain.Enums.RecurrenceType.Monthly,c.RecurrenceInterval>0?c.RecurrenceInterval:tx.RecurrenceInterval,(tx.RecurrenceIndex??1)-1):null;tx.Notes=c.Notes;tx.IsRecurring=c.IsRecurring||tx.IsRecurring;tx.RecurrenceType=c.RecurrenceType??tx.RecurrenceType;tx.RecurrenceInterval=Math.Max(1,c.RecurrenceInterval);tx.RecurrenceEndDate=c.RecurrenceEndDate;tx.TotalInstallments=c.TotalInstallments??tx.TotalInstallments; if(!string.IsNullOrWhiteSpace(tx.CategoryId)) _=await catRepo.GetByIdAsync(tx.CategoryId,c.UserId)??throw new ValidationException("Categoria invalida"); _=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); await txRepo.UpdateAsync(tx);} await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return targets.Select(x=>x.ToDto()).ToList();} static string StripInstallmentSuffix(string value){var idx=value.LastIndexOf(" (",StringComparison.Ordinal); return idx>0?value[..idx]:value;}}
public class DeleteRecurringTransactionHandler(ITransactionRepository txRepo,IAccountRepository accRepo,ICreditCardInvoiceRepository invoiceRepo,ICacheService cache):IRequestHandler<DeleteRecurringTransactionCommand>{public async Task Handle(DeleteRecurringTransactionCommand c,CancellationToken ct){var selected=await txRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transacao nao encontrada"); var targets=await RecurrenceScope.SelectAsync(txRepo,selected,c.UserId,c.Scope); foreach(var tx in targets){var acc=await accRepo.GetByIdAsync(tx.AccountId,c.UserId)??throw new ValidationException("Conta invalida"); if(acc.Type==AccountType.CreditCard&&!string.IsNullOrWhiteSpace(tx.CreditCardInvoiceId)){var invoice=await invoiceRepo.GetByIdAsync(tx.CreditCardInvoiceId,c.UserId); if(invoice is not null&&invoice.Status!=CreditCardInvoiceStatus.Paid){invoice.TotalAmount=Math.Max(0,invoice.TotalAmount-tx.Amount); await invoiceRepo.UpdateAsync(invoice); acc.CurrentBalance=await invoiceRepo.SumOpenByAccountAsync(acc.Id,c.UserId); await accRepo.UpdateAsync(acc);}} else if(tx.Status==TransactionStatus.Paid){acc.CurrentBalance-=FinanceMapper.Impact(tx.Type,tx.Amount); await accRepo.UpdateAsync(acc);} await txRepo.DeleteAsync(tx.Id,c.UserId);} await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct);}}
public static class RecurrenceScope { public static async Task<List<Transaction>> SelectAsync(ITransactionRepository repo,Transaction selected,string userId,string scope){if(!selected.RecurrenceGroupId.HasValue||scope=="this") return [selected]; var group=await repo.GetByRecurrenceGroupAsync(selected.RecurrenceGroupId.Value,userId); return scope switch{"future"=>group.Where(x=>x.Date>=selected.Date).ToList(),"all"=>group,_=>[selected]};}}

public class GetCreditCardInvoicesHandler(IAccountRepository accountRepo,ICreditCardInvoiceRepository invoiceRepo,ITransactionRepository txRepo):IRequestHandler<GetCreditCardInvoicesQuery,List<CreditCardInvoiceDto>>{public async Task<List<CreditCardInvoiceDto>> Handle(GetCreditCardInvoicesQuery q,CancellationToken ct){var account=await accountRepo.GetByIdAsync(q.AccountId,q.UserId)??throw new NotFoundException("Conta nao encontrada"); if(account.Type!=AccountType.CreditCard) throw new ValidationException("Conta nao e cartao de credito"); var invoices=await invoiceRepo.GetByAccountAsync(q.AccountId,q.UserId); var result=new List<CreditCardInvoiceDto>(); foreach(var invoice in invoices){result.Add(invoice.ToDto(await txRepo.GetByInvoiceIdAsync(invoice.Id,q.UserId)));} return result;}}
public class GetCreditCardInvoiceHandler(IAccountRepository accountRepo,ICreditCardInvoiceRepository invoiceRepo,ITransactionRepository txRepo):IRequestHandler<GetCreditCardInvoiceQuery,CreditCardInvoiceDto>{public async Task<CreditCardInvoiceDto> Handle(GetCreditCardInvoiceQuery q,CancellationToken ct){var account=await accountRepo.GetByIdAsync(q.AccountId,q.UserId)??throw new NotFoundException("Conta nao encontrada"); if(account.Type!=AccountType.CreditCard) throw new ValidationException("Conta nao e cartao de credito"); var invoice=await invoiceRepo.GetByPeriodAsync(q.AccountId,q.UserId,q.Month,q.Year); if(invoice is null){invoice=new CreditCardInvoice{UserId=q.UserId,AccountId=q.AccountId,Month=q.Month,Year=q.Year,DueDate=CreditCardInvoiceCalculator.DueDate(q.Month,q.Year,account.DueDay)}; await invoiceRepo.AddAsync(invoice);} return invoice.ToDto(await txRepo.GetByInvoiceIdAsync(invoice.Id,q.UserId));}}
public class PayCreditCardInvoiceHandler(IAccountRepository accountRepo,ICreditCardInvoiceRepository invoiceRepo,ITransactionRepository txRepo,ICacheService cache):IRequestHandler<PayCreditCardInvoiceCommand,CreditCardInvoiceDto>{public async Task<CreditCardInvoiceDto> Handle(PayCreditCardInvoiceCommand c,CancellationToken ct){if(c.Amount<=0) throw new ValidationException("Valor de pagamento deve ser positivo"); var invoice=await invoiceRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Fatura nao encontrada"); if(invoice.Status==CreditCardInvoiceStatus.Paid) throw new ValidationException("Fatura ja paga"); var card=await accountRepo.GetByIdAsync(invoice.AccountId,c.UserId)??throw new NotFoundException("Cartao nao encontrado"); var source=await accountRepo.GetByIdAsync(c.SourceAccountId,c.UserId)??throw new ValidationException("Conta de debito invalida"); if(source.Type==AccountType.CreditCard) throw new ValidationException("Pagamento de fatura deve sair de uma conta de debito"); source.CurrentBalance-=c.Amount; await accountRepo.UpdateAsync(source); invoice.Status=CreditCardInvoiceStatus.Paid; invoice.PaidAt=DateTime.UtcNow; await invoiceRepo.UpdateAsync(invoice); card.CurrentBalance=await invoiceRepo.SumOpenByAccountAsync(card.Id,c.UserId); await accountRepo.UpdateAsync(card); var tx=new Transaction{UserId=c.UserId,AccountId=source.Id,CategoryId="",Description=$"Pagamento fatura {card.Name} {invoice.Month:00}/{invoice.Year}",Amount=c.Amount,Type=TransactionType.Expense,Status=TransactionStatus.Paid,Date=DateTime.UtcNow,DueDate=invoice.DueDate,Notes="Pagamento de fatura de cartao de credito",CreditCardInvoiceId=invoice.Id}; await txRepo.AddAsync(tx); await cache.RemoveByPrefixAsync($"aurora:dashboard:{c.UserId}",ct); return invoice.ToDto(await txRepo.GetByInvoiceIdAsync(invoice.Id,c.UserId));}}

public static class BudgetMapper {
 public static BudgetDto ToBudgetDto(Category category,Budget? budget,decimal spent,int month,int year){var limit=budget?.LimitAmount; var usage=limit.HasValue&&limit.Value>0?Math.Round((spent/limit.Value)*100,2):0; return new BudgetDto(budget?.Id,category.Id,category.Name,category.Icon,category.Color,month,year,limit,spent,usage,budget is not null);}
}

public class GetBudgetsHandler(IBudgetRepository budgetRepo,ICategoryRepository categoryRepo,ITransactionRepository txRepo):IRequestHandler<GetBudgetsQuery,List<BudgetDto>>{public async Task<List<BudgetDto>> Handle(GetBudgetsQuery q,CancellationToken ct){var categories=(await categoryRepo.GetByUserAsync(q.UserId)).Where(x=>x.Type==CategoryType.Expense).OrderBy(x=>x.Name).ToList(); var budgets=(await budgetRepo.GetByMonthAsync(q.UserId,q.Month,q.Year)).ToDictionary(x=>x.CategoryId,x=>x); var spent=(await txRepo.CategoryExpenseAsync(q.UserId,q.Month,q.Year)).ToDictionary(x=>x.CategoryId,x=>x.Total); return categories.Select(category=>BudgetMapper.ToBudgetDto(category,budgets.GetValueOrDefault(category.Id),spent.GetValueOrDefault(category.Id),q.Month,q.Year)).OrderByDescending(x=>x.HasBudget&&x.LimitAmount>0?x.UsagePercentage:-1).ThenBy(x=>x.CategoryName).ToList();}}
public class UpsertBudgetHandler(IBudgetRepository budgetRepo,ICategoryRepository categoryRepo,ITransactionRepository txRepo):IRequestHandler<UpsertBudgetCommand,BudgetDto>{public async Task<BudgetDto> Handle(UpsertBudgetCommand c,CancellationToken ct){if(c.Month<1||c.Month>12) throw new ValidationException("Mes invalido"); if(c.Year<2000) throw new ValidationException("Ano invalido"); if(c.LimitAmount<=0) throw new ValidationException("Limite deve ser positivo"); var category=await categoryRepo.GetByIdAsync(c.CategoryId,c.UserId)??throw new ValidationException("Categoria invalida"); if(category.Type!=CategoryType.Expense) throw new ValidationException("Orcamento deve usar categoria de despesa"); var budget=await budgetRepo.GetByCategoryPeriodAsync(c.UserId,c.CategoryId,c.Month,c.Year); if(budget is null){budget=new Budget{UserId=c.UserId,CategoryId=c.CategoryId,Month=c.Month,Year=c.Year,LimitAmount=c.LimitAmount}; await budgetRepo.AddAsync(budget);} else {budget.LimitAmount=c.LimitAmount; await budgetRepo.UpdateAsync(budget);} var spent=(await txRepo.CategoryExpenseAsync(c.UserId,c.Month,c.Year)).FirstOrDefault(x=>x.CategoryId==c.CategoryId).Total; return BudgetMapper.ToBudgetDto(category,budget,spent,c.Month,c.Year);}}
public class DeleteBudgetHandler(IBudgetRepository budgetRepo):IRequestHandler<DeleteBudgetCommand>{public async Task Handle(DeleteBudgetCommand c,CancellationToken ct){var budget=await budgetRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Orcamento nao encontrado"); await budgetRepo.DeleteAsync(budget.Id,c.UserId);}}

public class GetTransfersHandler(ITransferRepository transferRepo):IRequestHandler<GetTransfersQuery,List<TransferDto>>{public async Task<List<TransferDto>> Handle(GetTransfersQuery q,CancellationToken ct)=>(await transferRepo.GetByFilterAsync(q.UserId,q.Month,q.Year)).Select(x=>x.ToDto()).ToList();}
public class CreateTransferHandler(ITransferRepository transferRepo,IAccountRepository accountRepo):IRequestHandler<CreateTransferCommand,TransferDto>{public async Task<TransferDto> Handle(CreateTransferCommand c,CancellationToken ct){if(c.Amount<=0) throw new ValidationException("Valor da transferencia deve ser positivo"); if(c.FromAccountId==c.ToAccountId) throw new ValidationException("Conta de origem e destino devem ser diferentes"); var from=await accountRepo.GetByIdAsync(c.FromAccountId,c.UserId)??throw new ValidationException("Conta de origem invalida"); var to=await accountRepo.GetByIdAsync(c.ToAccountId,c.UserId)??throw new ValidationException("Conta de destino invalida"); if(from.Type==AccountType.CreditCard||to.Type==AccountType.CreditCard) throw new ValidationException("Transferencia nao usa cartao de credito"); var originUpdated=false; var destinationUpdated=false; try{from.CurrentBalance-=c.Amount; await accountRepo.UpdateAsync(from); originUpdated=true; to.CurrentBalance+=c.Amount; await accountRepo.UpdateAsync(to); destinationUpdated=true; var transfer=new Transfer{UserId=c.UserId,FromAccountId=from.Id,ToAccountId=to.Id,Amount=c.Amount,Date=c.Date,Description=c.Description,Status=TransferStatus.Completed}; await transferRepo.AddAsync(transfer); return transfer.ToDto();}catch{if(destinationUpdated){to.CurrentBalance-=c.Amount; await accountRepo.UpdateAsync(to);} if(originUpdated){from.CurrentBalance+=c.Amount; await accountRepo.UpdateAsync(from);} throw;}}}
public class DeleteTransferHandler(ITransferRepository transferRepo,IAccountRepository accountRepo):IRequestHandler<DeleteTransferCommand>{public async Task Handle(DeleteTransferCommand c,CancellationToken ct){var transfer=await transferRepo.GetByIdAsync(c.Id,c.UserId)??throw new NotFoundException("Transferencia nao encontrada"); var from=await accountRepo.GetByIdAsync(transfer.FromAccountId,c.UserId)??throw new ValidationException("Conta de origem invalida"); var to=await accountRepo.GetByIdAsync(transfer.ToAccountId,c.UserId)??throw new ValidationException("Conta de destino invalida"); var originReverted=false; var destinationReverted=false; try{from.CurrentBalance+=transfer.Amount; await accountRepo.UpdateAsync(from); originReverted=true; to.CurrentBalance-=transfer.Amount; await accountRepo.UpdateAsync(to); destinationReverted=true; await transferRepo.DeleteAsync(transfer.Id,c.UserId);}catch{if(destinationReverted){to.CurrentBalance+=transfer.Amount; await accountRepo.UpdateAsync(to);} if(originReverted){from.CurrentBalance-=transfer.Amount; await accountRepo.UpdateAsync(from);} throw;}}}

public class GetMonthlySummaryHandler(IAccountRepository accountRepo,ITransactionRepository txRepo, ICacheService cache): IRequestHandler<GetMonthlySummaryQuery,MonthlySummaryDto>{ public async Task<MonthlySummaryDto> Handle(GetMonthlySummaryQuery q, CancellationToken ct){ var key=$"aurora:dashboard:{q.UserId}:{q.Month}:{q.Year}:v3"; var c=await cache.GetAsync<MonthlySummaryDto>(key,ct); if(c is not null) return c; var total=await accountRepo.GetTotalBalanceAsync(q.UserId); var i=await txRepo.SumAsync(q.UserId,q.Month,q.Year,TransactionType.Income,TransactionStatus.Paid); var e=await txRepo.SumAsync(q.UserId,q.Month,q.Year,TransactionType.Expense,TransactionStatus.Paid); var prev=new DateTime(q.Year,q.Month,1).AddMonths(-1); var prevIncome=await txRepo.SumAsync(q.UserId,prev.Month,prev.Year,TransactionType.Income,TransactionStatus.Paid); var prevExpense=await txRepo.SumAsync(q.UserId,prev.Month,prev.Year,TransactionType.Expense,TransactionStatus.Paid); var incomeVar=Variation(i,prevIncome); var expenseVar=Variation(e,prevExpense); var savings=i==0?0:Math.Round(((i-e)/i)*100,2); var pi=await txRepo.SumAsync(q.UserId,q.Month,q.Year,TransactionType.Income,TransactionStatus.Pending); var pe=await txRepo.SumAsync(q.UserId,q.Month,q.Year,TransactionType.Expense,TransactionStatus.Pending); var pc=await txRepo.CountAsync(q.UserId,q.Month,q.Year,TransactionStatus.Paid); var pdc=await txRepo.CountAsync(q.UserId,q.Month,q.Year,TransactionStatus.Pending); var recent=(await txRepo.RecentAsync(q.UserId)).Select(x=>x.ToDto()).ToList(); var upcoming=(await txRepo.UpcomingDueAsync(q.UserId,7)).Select(x=>x.ToUpcomingDueDto()).ToList(); var d=new MonthlySummaryDto(total,i,e,i-e,pi,pe,pc,pdc,recent,prevIncome,prevExpense,incomeVar,expenseVar,savings,upcoming); await cache.SetAsync(key,d,TimeSpan.FromMinutes(5),ct); return d; } static decimal Variation(decimal current,decimal previous)=>previous==0?(current==0?0:100):Math.Round(((current-previous)/previous)*100,2);}
public class UpcomingDuesHandler(ITransactionRepository txRepo):IRequestHandler<UpcomingDuesQuery,List<UpcomingDueDto>>{public async Task<List<UpcomingDueDto>> Handle(UpcomingDuesQuery q,CancellationToken ct)=>(await txRepo.UpcomingDueAsync(q.UserId,q.Days<=0?7:q.Days)).Select(x=>x.ToUpcomingDueDto()).OrderBy(x=>x.DueDate).ToList();}
public class GetCategoryExpensesHandler(ITransactionRepository txRepo, ICategoryRepository catRepo): IRequestHandler<GetCategoryExpensesQuery,List<CategoryExpenseDto>>{ public async Task<List<CategoryExpenseDto>> Handle(GetCategoryExpensesQuery q,CancellationToken ct){var grouped=await txRepo.CategoryExpenseAsync(q.UserId,q.Month,q.Year); var cats=(await catRepo.GetByUserAsync(q.UserId)).ToDictionary(x=>x.Id,x=>x); var total=grouped.Sum(x=>x.Total); return grouped.Select(x=>{cats.TryGetValue(x.CategoryId,out var c); var p=total==0?0:Math.Round((x.Total/total)*100,2); return new CategoryExpenseDto(x.CategoryId,c?.Name??"N/A",c?.Color??"#94a3b8",x.Total,p);}).OrderByDescending(x=>x.Total).ToList(); }}
public class GetCashFlowHandler(ITransactionRepository txRepo): IRequestHandler<GetCashFlowQuery,List<CashFlowItemDto>>{ public async Task<List<CashFlowItemDto>> Handle(GetCashFlowQuery q,CancellationToken ct)=>(await txRepo.CashFlowAsync(q.UserId,q.Year)).Select(x=>new CashFlowItemDto(x.Month,x.Income,x.Expense,x.Income-x.Expense)).ToList(); }
